<!DOCTYPE html>
<html lang="{{ str_replace('_', '-', app()->getLocale()) }}">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>AlfaWeb - {{ config('app.name', 'AlfaApps') }}</title>
    <link rel="icon" type="image/png" sizes="16x16" href="/assets/images/favicon.png">
    <link rel="stylesheet" href="/assets/icons/fontawesome/css/all.min.css">
    <style>
        :root{--primary:#5B5FEF;--primary-dark:#4347D6;--primary-light:#8E91F4;--coral:#FF6B81;--orange:#FFA552;--mint:#4FD1A5;--bg:#F2F4F8;--surface:#fff;--surface-alt:#F7F8FB;--text:#1F2233;--muted:#7A7E92;--border:#E5E7EE;--danger:#EF4444;--shadow:0 18px 44px rgba(17,26,64,.08)}
        *{box-sizing:border-box} body{margin:0;min-height:100vh;background:var(--bg);color:var(--text);font-family:'Plus Jakarta Sans',Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif} a{text-decoration:none;color:inherit} button,input,select,textarea{font:inherit}.app{display:grid;grid-template-columns:292px 1fr;min-height:100vh}.sidebar{position:sticky;top:0;height:100vh;padding:26px 20px;background:rgba(255,255,255,.78);backdrop-filter:blur(18px);border-right:1px solid rgba(229,231,238,.8)}.brand{display:flex;align-items:center;gap:12px;margin-bottom:30px}.brand-mark{width:52px;height:52px;border-radius:20px;display:grid;place-items:center;background:linear-gradient(135deg,var(--primary),var(--primary-light));color:white;font-weight:900;font-size:22px;box-shadow:0 18px 34px rgba(91,95,239,.28)}.brand-title{font-size:22px;font-weight:900;letter-spacing:-.04em}.brand-sub{display:block;color:var(--muted);font-size:12px;margin-top:2px}.nav{display:grid;gap:8px}.nav a,.logout{width:100%;min-height:48px;display:flex;align-items:center;gap:12px;padding:0 14px;border:0;border-radius:18px;background:transparent;color:var(--muted);font-weight:800;cursor:pointer;transition:.18s}.nav a:hover,.nav a.active{background:linear-gradient(135deg,var(--primary),var(--primary-dark));color:white;box-shadow:0 16px 32px rgba(91,95,239,.24)}.logout{margin-top:18px;color:var(--danger)}.logout:hover{background:#fff1f2}.main{padding:28px 30px 42px}.topbar{display:flex;align-items:center;justify-content:space-between;gap:18px;margin-bottom:24px}.eyebrow{margin:0 0 6px;color:var(--muted);font-weight:800;font-size:13px}.title{margin:0;font-size:clamp(30px,4vw,44px);letter-spacing:-.055em;line-height:1.05}.profile{display:flex;align-items:center;gap:12px;padding:12px 14px;border-radius:22px;background:var(--surface);box-shadow:var(--shadow);border:1px solid var(--border)}.avatar{width:44px;height:44px;border-radius:16px;display:grid;place-items:center;background:#EEF0FF;color:var(--primary);font-weight:900;overflow:hidden}.avatar img{width:100%;height:100%;object-fit:cover}.profile strong,.profile span{display:block}.profile span span{font-size:12px;color:var(--muted);margin-top:2px}.notice,.errors{margin-bottom:18px;padding:14px 16px;border-radius:18px;font-weight:800}.notice{background:#E9FBF4;color:#138A62}.errors{background:#FFF1F3;color:var(--danger)}.stats{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:16px;margin-bottom:18px}.card,.panel,.form-card{background:var(--surface);border:1px solid var(--border);border-radius:26px;box-shadow:var(--shadow)}.stat{padding:20px}.stat-head{display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:18px;color:var(--muted);font-size:13px;font-weight:900}.icon{width:44px;height:44px;border-radius:16px;display:grid;place-items:center}.i-primary{background:#EEF0FF;color:var(--primary)}.i-mint{background:#E7FBF4;color:#19A978}.i-coral{background:#FFF0F3;color:var(--coral)}.i-orange{background:#FFF6E9;color:var(--orange)}.stat-value{font-size:24px;font-weight:900;letter-spacing:-.04em}.grid-2{display:grid;grid-template-columns:1.1fr .9fr;gap:16px}.grid-3{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:16px}.panel{padding:22px}.panel h2,.form-card h2{margin:0 0 6px;font-size:21px;letter-spacing:-.03em}.panel p,.form-card p{margin:0 0 18px;color:var(--muted)}.hero-card{padding:26px;background:linear-gradient(135deg,var(--primary),var(--primary-dark));color:white;overflow:hidden;position:relative}.hero-card small{color:rgba(255,255,255,.72)}.hero-card .big{display:block;margin:10px 0 18px;font-size:34px;font-weight:900;letter-spacing:-.05em}.mini-row{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.mini{padding:14px;border-radius:18px;background:rgba(255,255,255,.14)}.category-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:14px}.category{padding:18px;border-radius:24px;background:var(--surface);border:1px solid var(--border);box-shadow:var(--shadow);transition:.18s}.category:hover{transform:translateY(-2px)}.category i{margin-bottom:14px}.category strong,.category span{display:block}.category span{margin-top:4px;color:var(--muted);font-size:13px}.form-card{padding:20px}.form-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.field{display:grid;gap:7px}.field.full{grid-column:1/-1}.field label{font-size:13px;font-weight:900}.field input,.field select,.field textarea{width:100%;border:1px solid var(--border);border-radius:16px;background:var(--surface-alt);padding:12px 14px;outline:none}.field input:focus,.field select:focus,.field textarea:focus{border-color:var(--primary);box-shadow:0 0 0 4px rgba(91,95,239,.1);background:white}.btn{display:inline-flex;align-items:center;justify-content:center;gap:8px;border:0;border-radius:16px;padding:12px 16px;font-weight:900;cursor:pointer}.btn-primary{background:linear-gradient(135deg,var(--primary),var(--primary-dark));color:white}.btn-soft{background:#EEF0FF;color:var(--primary)}.btn-danger{background:#FFF1F3;color:var(--danger)}.list{display:grid;gap:12px}.item{display:flex;align-items:center;justify-content:space-between;gap:14px;padding:16px;border-radius:20px;background:var(--surface-alt)}.item-main strong,.item-main span{display:block}.item-main span{margin-top:4px;color:var(--muted);font-size:13px}.badge{display:inline-flex;align-items:center;border-radius:999px;padding:7px 10px;font-size:12px;font-weight:900}.b-primary{background:#EEF0FF;color:var(--primary)}.b-mint{background:#E7FBF4;color:#159A70}.b-coral{background:#FFF0F3;color:var(--coral)}.b-orange{background:#FFF6E9;color:#D98312}.progress{height:12px;border-radius:999px;background:#EEF0FF;overflow:hidden}.progress span{display:block;height:100%;border-radius:inherit;background:linear-gradient(135deg,var(--primary),var(--primary-light))}.tabs{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px}.empty{padding:24px;border-radius:20px;background:var(--surface-alt);text-align:center;color:var(--muted);font-weight:700}.actions{display:flex;gap:8px;align-items:center}.text-income{color:#159A70}.text-expense{color:var(--danger)}.calendar-shell{display:grid;grid-template-columns:1fr 340px;gap:18px;margin-top:18px}.calendar-card{padding:22px}.calendar-head{display:flex;align-items:center;justify-content:space-between;gap:14px;margin-bottom:18px}.calendar-title{margin:0;font-size:24px;font-weight:900;letter-spacing:-.04em}.calendar-nav{display:flex;gap:8px}.calendar-nav a,.calendar-nav button{width:42px;height:42px;display:grid;place-items:center;border:0;border-radius:15px;background:#EEF0FF;color:var(--primary);font-weight:900;cursor:pointer}.calendar-grid.is-loading{opacity:.55}.calendar-week,.calendar-grid{display:grid;grid-template-columns:repeat(7,minmax(0,1fr));gap:10px}.calendar-week{margin-bottom:10px;color:var(--muted);font-size:12px;font-weight:900;text-align:center}.calendar-day{min-height:118px;padding:11px;border:1px solid var(--border);border-radius:20px;background:var(--surface-alt);overflow:hidden;text-align:left;color:var(--text);cursor:pointer;transition:.18s}.calendar-day:hover{transform:translateY(-1px);border-color:var(--primary)}.calendar-day.is-muted{opacity:.42}.calendar-day.is-today{border-color:var(--primary);box-shadow:0 0 0 4px rgba(91,95,239,.1);background:#fff}.calendar-day.is-selected{border-color:var(--primary);background:#EEF0FF;box-shadow:0 14px 28px rgba(91,95,239,.14)}.calendar-date{display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;font-weight:900}.calendar-date span:first-child{width:30px;height:30px;display:grid;place-items:center;border-radius:11px}.calendar-day.is-today .calendar-date span:first-child,.calendar-day.is-selected .calendar-date span:first-child{background:linear-gradient(135deg,var(--primary),var(--primary-dark));color:#fff}.calendar-count{font-size:11px;color:var(--primary);background:#fff;border-radius:999px;padding:4px 8px}.calendar-events{display:grid;gap:6px}.calendar-event{padding:7px 8px;border-radius:10px;background:#fff;color:var(--text);font-size:12px;font-weight:800;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;border-left:4px solid var(--primary)}.calendar-more{color:var(--muted);font-size:12px;font-weight:800}.schedule-side{display:grid;gap:14px}.schedule-legend{display:grid;gap:10px}.legend-item{display:flex;align-items:center;gap:10px;color:var(--muted);font-size:13px;font-weight:800}.legend-dot{width:12px;height:12px;border-radius:999px;background:var(--primary)}
        @media(max-width:1180px){.app{grid-template-columns:1fr}.sidebar{position:static;height:auto}.nav{grid-template-columns:repeat(3,minmax(0,1fr))}.stats,.category-grid{grid-template-columns:repeat(2,minmax(0,1fr))}.grid-2,.calendar-shell{grid-template-columns:1fr}}
        @media(max-width:720px){.main,.sidebar{padding:18px}.topbar,.item{align-items:flex-start;flex-direction:column}.stats,.grid-3,.category-grid,.form-grid,.mini-row,.nav{grid-template-columns:1fr}.profile{width:100%}.actions{width:100%;justify-content:flex-end}.title{font-size:30px}.calendar-week,.calendar-grid{gap:6px}.calendar-day{min-height:88px;padding:8px;border-radius:15px}.calendar-event{display:none}.calendar-count{font-size:10px;padding:3px 6px}.calendar-title{font-size:20px}}
    </style>
    @livewireStyles
</head>
<body>
    <livewire:web-app :page="$page" :finance-filter="request('type')" :work-target-filter="request('status')" :month="request('month')" />
    @livewireScripts
</body>
</html>
